(function(){
  if(window.__LV_SCHEDULE_MANAGER_V201__) return; window.__LV_SCHEDULE_MANAGER_V201__=true;
  var DAY_LABELS=['일','월','화','수','목','금','토'];
  var state={stores:[],store:'',groups:[],schedules:[],contents:[],activeGroup:null,activeSchedule:null,tab:'schedules'};
  function qs(s,root){return (root||document).querySelector(s)}
  function qsa(s,root){return Array.prototype.slice.call((root||document).querySelectorAll(s))}
  function h(s){return String(s==null?'':s).replace(/[&<>"']/g,function(c){return {'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'}[c]})}
  function toast(msg,err){var el=qs('#lvScheduleToast'); if(!el)return; el.textContent=msg; el.className='lvsch-toast'+(err?' err':''); el.style.display='block'; setTimeout(function(){el.style.display='none'},err?4500:2600)}
  async function api(path,opt){var res=await fetch(path+(path.indexOf('?')>=0?'&':'?')+'_lvts='+Date.now(),Object.assign({cache:'no-store',credentials:'same-origin',headers:{'content-type':'application/json'}},opt||{})); var data=null; try{data=await res.json()}catch(e){data={ok:false,error:'JSON 응답을 읽지 못했습니다.'}} if(!res.ok||data.ok===false) throw new Error(data.error||data.message||('HTTP '+res.status)); return data}
  function dayText(days){return (days||[]).map(function(d){return DAY_LABELS[Number(d)]}).filter(Boolean).join('·')||'-'}
  function groupName(id){var g=state.groups.find(function(x){return x.id===id}); return g?g.name:'-'}
  function nowKstParts(){var d=new Date(Date.now()+9*60*60*1000); return {day:d.getUTCDay(),minutes:d.getUTCHours()*60+d.getUTCMinutes(),time:String(d.getUTCHours()).padStart(2,'0')+':'+String(d.getUTCMinutes()).padStart(2,'0')}}
  function minutes(v){var m=String(v||'00:00').match(/^(\d{1,2}):(\d{2})$/); return m?Math.min(23,+m[1])*60+Math.min(59,+m[2]):0}
  function isActive(sch,day,min){if(!sch.enabled)return false; var days=(sch.days||[]).map(Number); if(days.indexOf(day)<0)return false; var st=minutes(sch.startTime), en=minutes(sch.endTime); if(st===en)return true; return st<en ? (min>=st&&min<en) : (min>=st||min<en)}
  function pickActive(day,min){var list=state.schedules.filter(function(s){return isActive(s,day,min)}).sort(function(a,b){return Number(b.priority||0)-Number(a.priority||0)}); return list[0]||null}
  function defaultGroup(){return state.groups.find(function(g){return g.isDefault})||state.groups[0]||null}
  function render(){ensureDom(); var p=qs('#lvSchedulePanel'); if(!p) return; var active=state.activeSchedule || pickActive(nowKstParts().day,nowKstParts().minutes); var activeGroup=state.activeGroup || (active?state.groups.find(function(g){return g.id===active.playlistGroupId}):defaultGroup());
    qs('[data-lvsch-store]').innerHTML=state.stores.map(function(s){return '<option value="'+h(s.slug)+'" '+(s.slug===state.store?'selected':'')+'>'+h(s.name||s.slug)+' · '+h(s.slug)+'</option>'}).join('');
    qs('[data-lvsch-current]').innerHTML='<div class="lvsch-current"><span class="lvsch-muted">현재 적용 중</span><strong>'+h(activeGroup?activeGroup.name:'기본 플레이리스트')+'</strong><span class="lvsch-muted">'+(active? h(active.name+' · '+dayText(active.days)+' '+active.startTime+'~'+active.endTime):'해당 시간대 스케줄 없음 · 기본 플레이리스트')+'</span></div>';
    qs('[data-lvsch-groups]').innerHTML=state.groups.length?state.groups.map(function(g){return '<div class="lvsch-chip '+(g.status!=='사용중'?'off':'')+'">'+h(g.name)+(g.isDefault?' · 기본':'')+' · '+Number(g.contentCount||0)+'개</div>'}).join(''):'<div class="lvsch-empty">플레이리스트 그룹이 없습니다.</div>';
    qsa('.lvsch-tab').forEach(function(t){t.classList.toggle('active',t.dataset.tab===state.tab)}); qsa('.lvsch-section').forEach(function(s){s.classList.toggle('active',s.dataset.section===state.tab)});
    renderSchedules(); renderContents(); renderPreview();
  }
  function renderSchedules(){var host=qs('[data-lvsch-schedule-list]'); if(!host)return; host.innerHTML=state.schedules.length?'<table class="lvsch-table"><thead><tr><th>사용</th><th>스케줄명</th><th>요일</th><th>시간</th><th>플레이리스트</th><th>관리</th></tr></thead><tbody>'+state.schedules.map(function(s){return '<tr><td><button class="lvsch-btn '+(s.enabled?'blue':'secondary')+'" data-toggle-sch="'+h(s.id)+'">'+(s.enabled?'ON':'OFF')+'</button></td><td><strong>'+h(s.name)+'</strong><br><span class="lvsch-muted">우선순위 '+Number(s.priority||100)+'</span></td><td>'+dayText(s.days)+'</td><td>'+h(s.startTime)+'~'+h(s.endTime)+'</td><td>'+h(groupName(s.playlistGroupId))+'</td><td><button class="lvsch-btn danger" data-del-sch="'+h(s.id)+'">삭제</button></td></tr>'}).join('')+'</tbody></table>':'<div class="lvsch-empty">아직 등록된 시간대별 송출 스케줄이 없습니다.</div>'}
  function renderContents(){var host=qs('[data-lvsch-content-list]'); if(!host)return; host.innerHTML=state.contents.length?'<table class="lvsch-table"><thead><tr><th>콘텐츠</th><th>타입</th><th>재생시간</th><th>플레이리스트</th></tr></thead><tbody>'+state.contents.map(function(c){return '<tr><td><strong>'+h(c.title||c.fileName)+'</strong><br><span class="lvsch-muted">'+h(c.fileName||c.id)+'</span></td><td>'+h(c.type)+'</td><td>'+Number(c.duration||20)+'초</td><td><select class="lvsch-select" data-content-group="'+h(c.id)+'">'+state.groups.map(function(g){return '<option value="'+h(g.id)+'" '+((c.playlistGroupId||'')===g.id?'selected':'')+'>'+h(g.name)+'</option>'}).join('')+'</select></td></tr>'}).join('')+'</tbody></table>':'<div class="lvsch-empty">좌측 콘텐츠가 없습니다. 기존 콘텐츠는 자동으로 기본 플레이리스트에 들어갑니다.</div>'}
  function renderPreview(){var host=qs('[data-lvsch-preview-result]'); if(!host)return; var d=Number(qs('[data-prev-day]')?.value||nowKstParts().day); var t=String(qs('[data-prev-time]')?.value||nowKstParts().time); var parts=t.split(':'); var min=Number(parts[0]||0)*60+Number(parts[1]||0); var sch=pickActive(d,min); var g=sch?state.groups.find(function(x){return x.id===sch.playlistGroupId}):defaultGroup(); host.innerHTML='<div class="lvsch-current"><span class="lvsch-muted">미리보기 결과</span><strong>'+h(g?g.name:'기본 플레이리스트')+'</strong><span class="lvsch-muted">'+(sch?h(sch.name+' 스케줄 적용'):DAY_LABELS[d]+' '+t+'에는 기본 플레이리스트 적용')+'</span></div>'}
  async function loadAll(){try{var stores=await api('/api/stores'); state.stores=stores.stores||[]; if(!state.stores.length){hideFab();return} if(!state.store) state.store=state.stores[0].slug; await loadStore(); showFab();}catch(e){hideFab();}}
  async function loadStore(){if(!state.store)return; var a=await Promise.all([api('/api/playlist-groups?store='+encodeURIComponent(state.store)),api('/api/playlist-schedules?store='+encodeURIComponent(state.store)),api('/api/contents?side=left&store='+encodeURIComponent(state.store))]); state.groups=a[0].groups||[]; state.schedules=a[1].schedules||[]; state.activeGroup=a[1].activeGroup||null; state.activeSchedule=a[1].activeSchedule||null; state.contents=a[2].contents||[]; render();}
  async function createGroup(){var name=prompt('새 플레이리스트 이름을 입력하세요. 예: 점심 플레이리스트'); if(!name)return; var dup=confirm('기본 플레이리스트 콘텐츠를 복제해서 시작할까요?'); var def=defaultGroup(); await api('/api/playlist-groups',{method:'POST',body:JSON.stringify({store:state.store,name:name,duplicateFromId:dup&&def?def.id:''})}); toast('플레이리스트 그룹을 만들었습니다.'); await loadStore();}
  async function createSchedule(){var days=qsa('[data-sch-day]:checked').map(function(x){return Number(x.value)}); var body={store:state.store,name:qs('[data-sch-name]').value.trim(),days:days,startTime:qs('[data-sch-start]').value,endTime:qs('[data-sch-end]').value,playlistGroupId:qs('[data-sch-group]').value,priority:Number(qs('[data-sch-priority]').value||100),enabled:true}; await api('/api/playlist-schedules',{method:'POST',body:JSON.stringify(body)}); qs('[data-sch-name]').value=''; toast('송출 스케줄을 저장했습니다.'); await loadStore();}
  async function toggleSchedule(id){var s=state.schedules.find(function(x){return x.id===id}); if(!s)return; await api('/api/playlist-schedules',{method:'PATCH',body:JSON.stringify({id:id,enabled:!s.enabled})}); toast('스케줄 상태를 변경했습니다.'); await loadStore();}
  async function deleteSchedule(id){if(!confirm('이 스케줄을 삭제할까요?'))return; await api('/api/playlist-schedules?id='+encodeURIComponent(id),{method:'DELETE'}); toast('스케줄을 삭제했습니다.'); await loadStore();}
  async function changeContentGroup(id,groupId){await api('/api/contents',{method:'PATCH',body:JSON.stringify({id:id,playlistGroupId:groupId})}); toast('콘텐츠 플레이리스트를 변경했습니다.'); await loadStore();}
  function openPanel(){ensureDom(); var p=qs('#lvSchedulePanel'); if(p){p.classList.add('is-open'); fillGroupSelects(); render();}} function showFab(){ensureMenuButton()} function hideFab(){var b=qs('#lvScheduleNavBtn'); if(b)b.style.display='none'}
  function ensureDom(){if(qs('#lvSchedulePanel'))return; var panel=document.createElement('div'); panel.id='lvSchedulePanel'; panel.innerHTML='<div class="lvsch-shell"><div class="lvsch-head"><div><p>LOCALVISION SCHEDULE MANAGER · CMS v2.0.2</p><h2>시간대별 송출 관리</h2><span>요일 + 시작시간 + 종료시간 + 플레이리스트 선택 방식의 CMS v2.0.2 정식 메뉴형 스케줄 기능입니다.</span></div><button class="lvsch-close" data-lvsch-close>닫기</button></div><div class="lvsch-body"><div class="lvsch-grid"><aside class="lvsch-card lvsch-stack"><h3>업체 선택</h3><select class="lvsch-select" data-lvsch-store></select><div data-lvsch-current></div><h3>플레이리스트 그룹</h3><div data-lvsch-groups class="lvsch-row"></div><button class="lvsch-btn blue" data-add-group>+ 플레이리스트 그룹 추가</button><p class="lvsch-muted">기존 콘텐츠는 자동으로 기본 플레이리스트에 배정됩니다. 필요한 콘텐츠만 점심/저녁/주말 그룹으로 옮기면 됩니다.</p></aside><main class="lvsch-stack"><div class="lvsch-card"><div class="lvsch-tabs"><button class="lvsch-tab active" data-tab="schedules">스케줄</button><button class="lvsch-tab" data-tab="contents">콘텐츠 연결</button><button class="lvsch-tab" data-tab="preview">미리보기</button></div><section class="lvsch-section active" data-section="schedules"><h3>스케줄 추가</h3><div class="lvsch-stack"><input class="lvsch-input" data-sch-name placeholder="스케줄명 예: 점심 메뉴"><div class="lvsch-days">'+DAY_LABELS.map(function(l,i){return '<label class="lvsch-day"><input type="checkbox" data-sch-day value="'+i+'" '+(i>=1&&i<=5?'checked':'')+'>'+l+'</label>'}).join('')+'</div><div class="lvsch-two"><input class="lvsch-input" type="time" data-sch-start value="11:00"><input class="lvsch-input" type="time" data-sch-end value="14:00"></div><div class="lvsch-two"><select class="lvsch-select" data-sch-group></select><label class="lvsch-priority-wrap"><span>우선순위</span><input class="lvsch-input" type="number" data-sch-priority value="100" placeholder="기본 100"><em>겹칠 때 숫자가 높은 스케줄이 우선 적용됩니다.</em></label></div><button class="lvsch-btn blue" data-save-sch>스케줄 저장</button></div><h3 style="margin-top:18px">등록된 스케줄</h3><div data-lvsch-schedule-list></div></section><section class="lvsch-section" data-section="contents"><h3>콘텐츠별 플레이리스트 배정</h3><p class="lvsch-muted">업로드 화면은 그대로 두고, 여기서 콘텐츠가 어느 플레이리스트에 들어갈지 지정합니다.</p><div data-lvsch-content-list></div></section><section class="lvsch-section" data-section="preview"><h3>시간 테스트</h3><div class="lvsch-two"><select class="lvsch-select" data-prev-day>'+DAY_LABELS.map(function(l,i){return '<option value="'+i+'">'+l+'요일</option>'}).join('')+'</select><input class="lvsch-input" type="time" data-prev-time></div><div style="margin-top:12px" data-lvsch-preview-result></div></section></div></main></div></div></div>'; document.body.appendChild(panel); var toastEl=document.createElement('div'); toastEl.id='lvScheduleToast'; toastEl.className='lvsch-toast'; document.body.appendChild(toastEl); bind();}
  function fillGroupSelects(){var html=state.groups.map(function(g){return '<option value="'+h(g.id)+'">'+h(g.name)+'</option>'}).join(''); var s=qs('[data-sch-group]'); if(s)s.innerHTML=html;}
  function bind(){var close=qs('[data-lvsch-close]'); if(close) close.onclick=function(){qs('#lvSchedulePanel').classList.remove('is-open')}; qs('[data-lvsch-store]').onchange=async function(e){state.store=e.target.value; await loadStore(); fillGroupSelects();}; qs('[data-add-group]').onclick=function(){createGroup().catch(function(e){toast(e.message,true)})}; qs('[data-save-sch]').onclick=function(){createSchedule().catch(function(e){toast(e.message,true)})}; qs('#lvSchedulePanel').addEventListener('click',function(e){var t=e.target.closest('[data-tab],[data-toggle-sch],[data-del-sch]'); if(!t)return; if(t.dataset.tab){state.tab=t.dataset.tab; render(); fillGroupSelects()} if(t.dataset.toggleSch)toggleSchedule(t.dataset.toggleSch).catch(function(x){toast(x.message,true)}); if(t.dataset.delSch)deleteSchedule(t.dataset.delSch).catch(function(x){toast(x.message,true)});}); qs('#lvSchedulePanel').addEventListener('change',function(e){if(e.target.matches('[data-content-group]')) changeContentGroup(e.target.dataset.contentGroup,e.target.value).catch(function(x){toast(x.message,true)}); if(e.target.matches('[data-prev-day],[data-prev-time]')) renderPreview();});}

  function ensureMenuButton(){
    var nav=qs('.sidebar nav')||qs('nav');
    if(!nav) return;
    var existing=qs('#lvScheduleNavBtn');
    if(existing){existing.style.display='flex'; return;}
    var btn=document.createElement('button');
    btn.id='lvScheduleNavBtn';
    btn.type='button';
    btn.className='lvsch-nav-btn';
    btn.innerHTML='<span class="lvsch-nav-icon">⏱</span><span>시간대별 송출</span>';
    btn.onclick=function(e){e.preventDefault(); e.stopPropagation(); openPanel();};
    var buttons=qsa('button',nav);
    var settings=buttons.find(function(b){return (b.textContent||'').indexOf('설정')>=0});
    if(settings) nav.insertBefore(btn,settings); else nav.appendChild(btn);
  }
  function startMenuObserver(){
    ensureMenuButton();
    setInterval(ensureMenuButton,2000);
    try{new MutationObserver(ensureMenuButton).observe(document.body,{childList:true,subtree:true});}catch(e){}
  }

  var oldRender=render; render=function(){oldRender(); fillGroupSelects(); var pt=qs('[data-prev-time]'); if(pt&&!pt.value)pt.value=nowKstParts().time;};
  function init(){ensureDom(); startMenuObserver(); loadAll(); setInterval(loadAll,15000)}
  if(document.readyState==='loading')document.addEventListener('DOMContentLoaded',init); else init();
})();
